    public static string GetTier(string entry) =>
        CardTable.TryGetValue(entry, out var v) && v.Tier != "?" ? v.Tier : null;

    public static string[] GetArchetypes(string entry) =>
        CardTable.TryGetValue(entry, out var v)
            ? (v.Archs.Length == 0 ? System.Array.Empty<string>() : v.Archs.Split(','))
            : null;  // null = card unknown to the table (fall back to signals)
